// agentLimitSummary renders a human sentence for the saved limits.
func agentLimitSummary(perUser, perCommunity int) string {
	user := "unlimited per member"
	if perUser > 0 {
		user = itoa(perUser) + "/min per member"
	}
	comm := "unlimited community-wide"
	if perCommunity > 0 {
		comm = itoa(perCommunity) + "/min community-wide"
	}
	return user + ", " + comm + "."
}

